create extension if not exists "uuid-ossp";
create table if not exists companies (id uuid primary key default uuid_generate_v4(), name text not null, document text, plan text default 'starter', status text default 'active', settings jsonb default '{}', created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists users (id uuid primary key default uuid_generate_v4(), company_id uuid references companies(id) on delete cascade, name text not null, email text not null unique, role text default 'admin', password_hash text, status text default 'active', created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists oauth_tokens (id text primary key, company_id uuid references companies(id) on delete cascade, marketplace text not null, access_token text, refresh_token text, user_id text, expires_in integer, token_type text default 'Bearer', scope text, created_at timestamptz default now(), updated_at timestamptz default now(), unique(company_id, marketplace));
create table if not exists logs (id uuid primary key default uuid_generate_v4(), company_id uuid references companies(id) on delete cascade, event_type text not null, message text, payload jsonb default '{}', created_at timestamptz default now());